import { Autumn } from 'autumn-js';

/**
 * Resilient feature check with fail-open pattern
 * @param {string} customerId - The customer ID
 * @param {string} featureId - The feature ID
 * @returns {Promise<{allowed: boolean, source: string}>} - Check result with source
 */
export async function resilientCheck(customerId, featureId) {
  const autumn = new Autumn({
    secretKey: process.env.AUTUMN_SECRET_KEY,
  });

  try {
    const result = await autumn.customers.check({ customerId, featureId });
    return { allowed: true, source: 'autumn' };
  } catch (error) {
    console.error('AUTUMN UNREACHABLE, FAILING OPEN');
    return { allowed: true, source: 'fail-open' };
  }
}

/**
 * Strict feature check without fail-open
 * @param {string} customerId - The customer ID
 * @param {string} featureId - The feature ID
 * @returns {Promise<{allowed: boolean, source: string}>} - Check result with source
 */
export async function resilientCheckStrict(customerId, featureId) {
  const autumn = new Autumn({
    secretKey: process.env.AUTUMN_SECRET_KEY,
    failOpen: false,
  });

  try {
    const result = await autumn.customers.check({ customerId, featureId });
    return { allowed: result.allowed, source: 'autumn-strict' };
  } catch (error) {
    // Re-throw any errors - does not fail open
    throw error;
  }
}

