import { resilientCheck } from './resilient_check.js';
import { writeFile } from 'fs/promises';

async function main() {
  try {
    const result = await resilientCheck('user_test_001', 'messages');

    // Write result to check_result.json
    await writeFile('check_result.json', JSON.stringify(result, null, 2));

    console.log('Check completed successfully');
    console.log('Result:', result);
  } catch (error) {
    console.error('Error running demo check:', error);
    process.exit(1);
  }
}

main();

